// Obtener el primer elemento del array de entrada (el nodo anterior debe entregar el JSON mostrado)
const inputData = $input.first().json;

// Verificar que exista la propiedad "output" y que sea un string
if (!inputData.output || typeof inputData.output !== 'string') {
  throw new Error('La propiedad "output" no existe o no es un string válido');
}

// Parsear el string JSON interno
let parsedOutput;
try {
  parsedOutput = JSON.parse(inputData.output);
} catch (error) {
  throw new Error(`Error al parsear el JSON de output: ${error.message}`);
}

// Construir el objeto final con todos los campos necesarios para los nodos siguientes
const processedData = {
  // Datos principales del análisis
  ticketId: parsedOutput.ticketId,
  categoria_ia: parsedOutput.categoria_ia,
  prioridad: parsedOutput.prioridad,
  confianza: parsedOutput.confianza,
  peligro_inminente: parsedOutput.peligro_inminente,
  palabras_clave_detectadas: parsedOutput.palabras_clave_detectadas,
  coherencia_texto_imagen: parsedOutput.coherencia_texto_imagen,
  validacion_coordenadas: parsedOutput.validacion_coordenadas,
  resumen_ia: parsedOutput.resumen_ia,

  // Campo adicional para facilitar el uso en notificaciones (por ejemplo, prioridad en texto)
  prioridad_texto: parsedOutput.prioridad === 'MODERADA' ? 'Moderada' : 
                   (parsedOutput.prioridad === 'ALTA' ? 'Alta' : 'Baja'),

  // Timestamp de procesamiento (opcional, útil para registro)
  timestamp_procesamiento: new Date().toISOString()
};

// Devolver el objeto procesado para los nodos siguientes
return [processedData];

